{"file_text": ".settings-layout {
    display: grid;
    grid-template-columns: 220px 1fr;
    gap: 2rem;
    min-height: 600px;
}

/* Sidebar */
.settings-sidebar {
    display: flex;
    flex-direction: column;
    gap: 0.25rem;
    background: #f8f9fa;
    border-radius: 0.5rem;
    padding: 0.75rem;
    height: fit-content;
    position: sticky;
    top: 1rem;
}

.settings-nav-item {
    display: flex;
    align-items: center;
    gap: 0.75rem;
    padding: 0.65rem 1rem;
    border: none;
    background: transparent;
    border-radius: 0.375rem;
    font-size: 0.95rem;
    color: #495057;
    cursor: pointer;
    transition: all 0.15s ease;
    text-align: left;
    width: 100%;
}

.settings-nav-item:hover {
    background: #e9ecef;
    color: #212529;
}

.settings-nav-item.active {
    background: #0d6efd;
    color: #fff;
    font-weight: 600;
}

.settings-nav-icon {
    font-size: 1.1rem;
    width: 1.5rem;
    text-align: center;
}

/* Content */
.settings-content {
    min-width: 0;
}

.settings-section-title {
    margin-bottom: 1.25rem;
    font-weight: 700;
}

.settings-card {
    background: #fff;
    border: 1px solid #dee2e6;
    border-radius: 0.5rem;
    padding: 1.5rem;
}

/* Avatar */
.avatar-section {
    display: flex;
    align-items: flex-start;
    gap: 1.5rem;
}

.avatar-preview {
    flex-shrink: 0;
    width: 96px;
    height: 96px;
    border-radius: 50%;
    overflow: hidden;
    background: #e9ecef;
    display: flex;
    align-items: center;
    justify-content: center;
    border: 3px solid #dee2e6;
}

.avatar-img {
    width: 100%;
    height: 100%;
    object-fit: cover;
}

.avatar-placeholder {
    font-size: 2.5rem;
    color: #adb5bd;
}

.avatar-url-display {
    flex: 1;
    min-width: 0;
}

/* Expandable panel */
.cursor-pointer {
    cursor: pointer;
}

.expand-icon {
    font-size: 0.85rem;
    color: #6c757d;
}

/* Appearance preview */
.appearance-preview {
    border-radius: 0.5rem;
    border: 1px solid #dee2e6;
    transition: all 0.2s ease;
}

/* Toast */
.settings-toast {
    position: fixed;
    bottom: 1.5rem;
    right: 1.5rem;
    background: #198754;
    color: #fff;
    padding: 0.75rem 1.25rem;
    border-radius: 0.5rem;
    display: flex;
    align-items: center;
    gap: 1rem;
    box-shadow: 0 0.25rem 1rem rgba(0,0,0,0.15);
    z-index: 1100;
    animation: toast-slide-in 0.3s ease;
}

.settings-toast-error {
    background: #dc3545;
}

@@keyframes toast-slide-in {
    from {
        transform: translateY(1rem);
        opacity: 0;
    }
    to {
        transform: translateY(0);
        opacity: 1;
    }
}

/* Responsive */
@@media (max-width: 768px) {
    .settings-layout {
        grid-template-columns: 1fr;
    }

    .settings-sidebar {
        flex-direction: row;
        overflow-x: auto;
        position: static;
    }

    .settings-nav-item {
        white-space: nowrap;
    }
}
