@page "/settings"
@using sv_ff15f925ad964178838dae9757c0e8b3.Models
@inject ISettingsService SettingsService
@rendermode InteractiveServer

<PageTitle>Settings</PageTitle>

<h1 class="mb-4">Settings</h1>

@if (_loading)
{
    <div class="d-flex justify-content-center py-5">
        <div class="spinner-border" role="status">
            <span class="visually-hidden">Loading...</span>
        </div>
    </div>
}
else
{
    <div class="settings-layout">
        <!-- Sidebar Navigation -->
        <nav class="settings-sidebar" role="tablist">
            @foreach (var section in _sections)
            {
                <button class="settings-nav-item @(section == _activeSection ? "active" : "")"
                        role="tab"
                        aria-selected="@(section == _activeSection)"
                        @onclick="() => SetActiveSection(section)">
                    <span class="settings-nav-icon">@GetSectionIcon(section)</span>
                    <span>@section</span>
                </button>
            }
        </nav>

        <!-- Main Content -->
        <div class="settings-content">
            @switch (_activeSection)
            {
                case "Profile":
                    @RenderProfile()
                    break;
                case "Notifications":
                    @RenderNotifications()
                    break;
                case "Security":
                    @RenderSecurity()
                    break;
                case "Appearance":
                    @RenderAppearance()
                    break;
            }
        </div>
    </div>
}

<!-- Toast Notification -->
@if (_toastVisible)
{
    <div class="settings-toast @(_toastIsError ? "settings-toast-error" : "")">
        <span>@_toastMessage</span>
        <button class="btn-close btn-close-white btn-sm" @onclick="() => _toastVisible = false"></button>
    </div>
}

<!-- Session Revoke Confirmation Modal -->
@if (_showRevokeConfirm)
{
    <div class="modal-backdrop fade show"></div>
    <div class="modal fade show d-block" tabindex="-1" role="dialog">
        <div class="modal-dialog modal-dialog-centered">
            <div class="modal-content">
                <div class="modal-header">
                    <h5 class="modal-title">Revoke Session</h5>
                    <button type="button" class="btn-close" @onclick="CancelRevoke"></button>
                </div>
                <div class="modal-body">
                    <p>Are you sure you want to revoke the session on <strong>@_sessionToRevoke?.Device</strong> from <strong>@_sessionToRevoke?.Location</strong>?</p>
                    <p class="text-muted mb-0">This will immediately sign out that device.</p>
                </div>
                <div class="modal-footer">
                    <button type="button" class="btn btn-secondary" @onclick="CancelRevoke">Cancel</button>
                    <button type="button" class="btn btn-danger" @onclick="ConfirmRevoke" disabled="@_revoking">
                        @if (_revoking)
                        {
                            <span class="spinner-border spinner-border-sm me-1"></span>
                        }
                        Revoke Session
                    </button>
                </div>
            </div>
        </div>
    </div>
}

@code {
    private readonly string[] _sections = ["Profile", "Notifications", "Security", "Appearance"];
    private string _activeSection = "Profile";
    private bool _loading = true;

    // Toast
    private bool _toastVisible;
    private string _toastMessage = "";
    private bool _toastIsError;
    private CancellationTokenSource? _toastCts;

    // Profile
    private UserProfile? _savedProfile;
    private string _displayName = "";
    private string _email = "";
    private string _bio = "";
    private string _avatarUrl = "";

    // Notifications
    private bool _emailNotifications;
    private bool _pushNotifications;
    private bool _weeklyDigest;
    private List<string> _allChannels = [];
    private HashSet<string> _mutedChannels = [];

    // Security
    private SecuritySettings? _security;
    private bool _twoFactorEnabled;
    private bool _passwordPanelOpen;
    private string _currentPassword = "";
    private string _newPassword = "";
    private string _confirmPassword = "";
    private bool _changingPassword;
    private bool _showRevokeConfirm;
    private ActiveSession? _sessionToRevoke;
    private bool _revoking;
    private const string CurrentSessionId = "sess-current";

    // Appearance
    private string _theme = "Light";
    private string _fontSize = "Medium";
    private string _language = "English";
    private bool _compactMode;
    private readonly string[] _themes = ["Light", "Dark", "System"];
    private readonly string[] _fontSizes = ["Small", "Medium", "Large"];
    private readonly string[] _languages = ["English", "Spanish", "French", "German", "Japanese", "Chinese"];

    protected override async Task OnInitializedAsync()
    {
        await LoadAllSettings();
        _loading = false;
    }

    private async Task LoadAllSettings()
    {
        var profileTask = SettingsService.GetProfileAsync();
        var notifTask = SettingsService.GetNotificationPrefsAsync();
        var securityTask = SettingsService.GetSecuritySettingsAsync();
        var appearanceTask = SettingsService.GetAppearanceAsync();

        await Task.WhenAll(profileTask, notifTask, securityTask, appearanceTask);

        // Profile
        _savedProfile = profileTask.Result;
        ApplyProfile(_savedProfile);

        // Notifications
        var notif = notifTask.Result;
        _emailNotifications = notif.EmailNotifications;
        _pushNotifications = notif.PushNotifications;
        _weeklyDigest = notif.WeeklyDigest;
        _allChannels = new List<string>(notif.MutedChannels.Count > 0
            ? notif.MutedChannels
            : ["general", "announcements", "random"]);
        _mutedChannels = new HashSet<string>(notif.MutedChannels);

        // Security
        _security = securityTask.Result;
        _twoFactorEnabled = _security.TwoFactorEnabled;

        // Appearance
        var appearance = appearanceTask.Result;
        _theme = appearance.Theme;
        _fontSize = appearance.FontSize;
        _language = appearance.Language;
        _compactMode = appearance.CompactMode;
    }

    private void ApplyProfile(UserProfile profile)
    {
        _displayName = profile.DisplayName;
        _email = profile.Email;
        _bio = profile.Bio;
        _avatarUrl = profile.AvatarUrl;
    }

    private void SetActiveSection(string section)
    {
        _activeSection = section;
    }

    private static string GetSectionIcon(string section) => section switch
    {
        "Profile" => "👤",
        "Notifications" => "🔔",
        "Security" => "🔒",
        "Appearance" => "🎨",
        _ => "⚙️"
    };

    // ── Toast ──

    private async Task ShowToast(string message, bool isError = false)
    {
        _toastCts?.Cancel();
        _toastCts = new CancellationTokenSource();
        var token = _toastCts.Token;

        _toastMessage = message;
        _toastIsError = isError;
        _toastVisible = true;
        StateHasChanged();

        try
        {
            await Task.Delay(4000, token);
            _toastVisible = false;
            StateHasChanged();
        }
        catch (TaskCanceledException) { }
    }

    // ── Profile ──

    private async Task SaveProfile()
    {
        var profile = new UserProfile(_displayName, _email, _avatarUrl, _bio);
        await SettingsService.SaveProfileAsync(profile);
        _savedProfile = profile;
        await ShowToast("Profile saved successfully!");
    }

    private void DiscardProfileChanges()
    {
        if (_savedProfile is not null)
        {
            ApplyProfile(_savedProfile);
        }
    }

    private bool ProfileHasChanges =>
        _savedProfile is not null &&
        (_displayName != _savedProfile.DisplayName ||
         _email != _savedProfile.Email ||
         _bio != _savedProfile.Bio ||
         _avatarUrl != _savedProfile.AvatarUrl);

    private RenderFragment RenderProfile() => __builder =>
    {
        <h3 class="settings-section-title">Profile</h3>

        <div class="settings-card">
            <!-- Avatar Preview -->
            <div class="avatar-section mb-4">
                <div class="avatar-preview">
                    @if (!string.IsNullOrWhiteSpace(_avatarUrl))
                    {
                        <img src="@_avatarUrl" alt="Avatar" class="avatar-img" />
                    }
                    else
                    {
                        <div class="avatar-placeholder">👤</div>
                    }
                </div>
                <div class="avatar-url-display">
                    <label class="form-label fw-semibold">Avatar URL</label>
                    <input type="url" class="form-control" @bind="_avatarUrl" placeholder="https://example.com/avatar.png" />
                </div>
            </div>

            <!-- Fields -->
            <div class="mb-3">
                <label class="form-label fw-semibold">Display Name</label>
                <input type="text" class="form-control" @bind="_displayName" />
            </div>

            <div class="mb-3">
                <label class="form-label fw-semibold">Email</label>
                <input type="email" class="form-control" @bind="_email" />
            </div>

            <div class="mb-3">
                <label class="form-label fw-semibold">Bio</label>
                <textarea class="form-control" rows="4" @bind="_bio"></textarea>
            </div>

            <div class="d-flex gap-2">
                <button class="btn btn-primary" @onclick="SaveProfile">
                    Save Changes
                </button>
                <button class="btn btn-outline-secondary" @onclick="DiscardProfileChanges" disabled="@(!ProfileHasChanges)">
                    Discard Changes
                </button>
            </div>
        </div>
    };

    // ── Notifications ──

    private void ToggleMutedChannel(string channel, bool muted)
    {
        if (muted)
            _mutedChannels.Add(channel);
        else
            _mutedChannels.Remove(channel);
    }

    private async Task SaveNotifications()
    {
        var prefs = new NotificationPrefs(
            _emailNotifications,
            _pushNotifications,
            _weeklyDigest,
            _mutedChannels.ToList()
        );
        await SettingsService.SaveNotificationPrefsAsync(prefs);
        await ShowToast("Notification preferences saved!");
    }

    private RenderFragment RenderNotifications() => __builder =>
    {
        <h3 class="settings-section-title">Notifications</h3>

        <div class="settings-card">
            <h5 class="mb-3">General</h5>

            <div class="form-check form-switch mb-3">
                <input class="form-check-input" type="checkbox" id="emailNotif" @bind="_emailNotifications" />
                <label class="form-check-label" for="emailNotif">Email Notifications</label>
            </div>

            <div class="form-check form-switch mb-3">
                <input class="form-check-input" type="checkbox" id="pushNotif" @bind="_pushNotifications" />
                <label class="form-check-label" for="pushNotif">Push Notifications</label>
            </div>

            <div class="form-check form-switch mb-4">
                <input class="form-check-input" type="checkbox" id="weeklyDigest" @bind="_weeklyDigest" />
                <label class="form-check-label" for="weeklyDigest">Weekly Digest</label>
            </div>

            <h5 class="mb-3">Channel Muting</h5>
            <p class="text-muted small">Check channels you want to mute.</p>

            <div class="channel-list mb-4">
                @foreach (var channel in _allChannels)
                {
                    var ch = channel;
                    <div class="form-check mb-2">
                        <input class="form-check-input" type="checkbox" id="@($"ch-{ch}")"
                               checked="@_mutedChannels.Contains(ch)"
                               @onchange="e => ToggleMutedChannel(ch, (bool)(e.Value ?? false))" />
                        <label class="form-check-label" for="@($"ch-{ch}")">
                            #@ch
                        </label>
                    </div>
                }
            </div>

            <button class="btn btn-primary" @onclick="SaveNotifications">
                Save Preferences
            </button>
        </div>
    };

    // ── Security ──

    private async Task ChangePassword()
    {
        if (string.IsNullOrWhiteSpace(_currentPassword) ||
            string.IsNullOrWhiteSpace(_newPassword) ||
            string.IsNullOrWhiteSpace(_confirmPassword))
        {
            await ShowToast("All password fields are required.", true);
            return;
        }

        if (_newPassword != _confirmPassword)
        {
            await ShowToast("New password and confirmation do not match.", true);
            return;
        }

        if (_newPassword.Length < 8)
        {
            await ShowToast("New password must be at least 8 characters.", true);
            return;
        }

        _changingPassword = true;
        StateHasChanged();

        await SettingsService.ChangePasswordAsync(_currentPassword, _newPassword);

        _currentPassword = "";
        _newPassword = "";
        _confirmPassword = "";
        _changingPassword = false;
        _passwordPanelOpen = false;

        _security = await SettingsService.GetSecuritySettingsAsync();

        await ShowToast("Password updated successfully!");
    }

    private void RequestRevoke(ActiveSession session)
    {
        _sessionToRevoke = session;
        _showRevokeConfirm = true;
    }

    private void CancelRevoke()
    {
        _sessionToRevoke = null;
        _showRevokeConfirm = false;
    }

    private async Task ConfirmRevoke()
    {
        if (_sessionToRevoke is null) return;

        _revoking = true;
        StateHasChanged();

        await SettingsService.RevokeSessionAsync(_sessionToRevoke.Id);
        _security = await SettingsService.GetSecuritySettingsAsync();

        _revoking = false;
        _showRevokeConfirm = false;
        _sessionToRevoke = null;

        await ShowToast("Session revoked.");
    }

    private RenderFragment RenderSecurity() => __builder =>
    {
        <h3 class="settings-section-title">Security</h3>

        <!-- Change Password -->
        <div class="settings-card mb-3">
            <div class="d-flex justify-content-between align-items-center cursor-pointer"
                 @onclick="() => _passwordPanelOpen = !_passwordPanelOpen">
                <h5 class="mb-0">Change Password</h5>
                <span class="expand-icon">@(_passwordPanelOpen ? "▲" : "▼")</span>
            </div>

            @if (_passwordPanelOpen)
            {
                <div class="mt-3">
                    <div class="mb-3">
                        <label class="form-label fw-semibold">Current Password</label>
                        <input type="password" class="form-control" @bind="_currentPassword" />
                    </div>
                    <div class="mb-3">
                        <label class="form-label fw-semibold">New Password</label>
                        <input type="password" class="form-control" @bind="_newPassword" />
                    </div>
                    <div class="mb-3">
                        <label class="form-label fw-semibold">Confirm Password</label>
                        <input type="password" class="form-control" @bind="_confirmPassword" />
                    </div>
                    <button class="btn btn-primary" @onclick="ChangePassword" disabled="@_changingPassword">
                        @if (_changingPassword)
                        {
                            <span class="spinner-border spinner-border-sm me-1"></span>
                        }
                        Update Password
                    </button>
                </div>
            }
        </div>

        <!-- Two-Factor Auth -->
        <div class="settings-card mb-3">
            <div class="d-flex justify-content-between align-items-center">
                <div>
                    <h5 class="mb-1">Two-Factor Authentication</h5>
                    <span class="badge @(_twoFactorEnabled ? "bg-success" : "bg-secondary")">
                        @(_twoFactorEnabled ? "Enabled" : "Disabled")
                    </span>
                </div>
                <div class="form-check form-switch">
                    <input class="form-check-input" type="checkbox" @bind="_twoFactorEnabled" />
                </div>
            </div>
            @if (_security?.LastPasswordChange is not null)
            {
                <p class="text-muted small mt-2 mb-0">
                    Last password change: @_security.LastPasswordChange.Value.ToString("MMMM dd, yyyy")
                </p>
            }
        </div>

        <!-- Active Sessions -->
        <div class="settings-card">
            <h5 class="mb-3">Active Sessions</h5>

            @if (_security?.Sessions is { Count: > 0 })
            {
                <div class="table-responsive">
                    <table class="table table-hover mb-0">
                        <thead>
                            <tr>
                                <th>Device</th>
                                <th>Location</th>
                                <th>Last Active</th>
                                <th></th>
                            </tr>
                        </thead>
                        <tbody>
                            @foreach (var session in _security.Sessions)
                            {
                                var isCurrent = session.Id == CurrentSessionId;
                                <tr>
                                    <td>
                                        @session.Device
                                        @if (isCurrent)
                                        {
                                            <span class="badge bg-primary ms-1">Current</span>
                                        }
                                    </td>
                                    <td>@session.Location</td>
                                    <td>@FormatLastActive(session.LastActive)</td>
                                    <td class="text-end">
                                        @if (!isCurrent)
                                        {
                                            <button class="btn btn-outline-danger btn-sm"
                                                    @onclick="() => RequestRevoke(session)">
                                                Revoke
                                            </button>
                                        }
                                    </td>
                                </tr>
                            }
                        </tbody>
                    </table>
                </div>
            }
            else
            {
                <p class="text-muted">No active sessions found.</p>
            }
        </div>
    };

    private static string FormatLastActive(DateTime lastActive)
    {
        var diff = DateTime.UtcNow - lastActive;
        if (diff.TotalMinutes < 1) return "Just now";
        if (diff.TotalHours < 1) return $"{(int)diff.TotalMinutes}m ago";
        if (diff.TotalDays < 1) return $"{(int)diff.TotalHours}h ago";
        return $"{(int)diff.TotalDays}d ago";
    }

    // ── Appearance ──

    private async Task SaveAppearance()
    {
        var settings = new AppearanceSettings(_theme, _fontSize, _language, _compactMode);
        await SettingsService.SaveAppearanceAsync(settings);
        await ShowToast("Appearance settings saved!");
    }

    private string PreviewFontSize => _fontSize switch
    {
        "Small" => "0.85rem",
        "Large" => "1.15rem",
        _ => "1rem"
    };

    private string PreviewBackground => _theme switch
    {
        "Dark" => "#1e1e1e",
        "System" => "#f0f0f0",
        _ => "#ffffff"
    };

    private string PreviewTextColor => _theme switch
    {
        "Dark" => "#e0e0e0",
        _ => "#212529"
    };

    private RenderFragment RenderAppearance() => __builder =>
    {
        <h3 class="settings-section-title">Appearance</h3>

        <div class="settings-card mb-3">
            <!-- Theme -->
            <h5 class="mb-3">Theme</h5>
            <div class="d-flex gap-3 mb-4">
                @foreach (var t in _themes)
                {
                    var theme = t;
                    <div class="form-check">
                        <input class="form-check-input" type="radio" name="theme" id="@($"theme-{theme}")"
                               value="@theme" checked="@(_theme == theme)"
                               @onchange="() => _theme = theme" />
                        <label class="form-check-label" for="@($"theme-{theme}")">@theme</label>
                    </div>
                }
            </div>

            <!-- Font Size -->
            <h5 class="mb-3">Font Size</h5>
            <div class="d-flex gap-3 mb-4">
                @foreach (var fs in _fontSizes)
                {
                    var size = fs;
                    <div class="form-check">
                        <input class="form-check-input" type="radio" name="fontSize" id="@($"fs-{size}")"
                               value="@size" checked="@(_fontSize == size)"
                               @onchange="() => _fontSize = size" />
                        <label class="form-check-label" for="@($"fs-{size}")">@size</label>
                    </div>
                }
            </div>

            <!-- Language -->
            <h5 class="mb-3">Language</h5>
            <div class="mb-4" style="max-width: 300px;">
                <select class="form-select" @bind="_language">
                    @foreach (var lang in _languages)
                    {
                        <option value="@lang">@lang</option>
                    }
                </select>
            </div>

            <!-- Compact Mode -->
            <div class="form-check form-switch mb-4">
                <input class="form-check-input" type="checkbox" id="compactMode" @bind="_compactMode" />
                <label class="form-check-label" for="compactMode">Compact Mode</label>
            </div>

            <button class="btn btn-primary" @onclick="SaveAppearance">Save</button>
        </div>

        <!-- Live Preview -->
        <div class="settings-card">
            <h5 class="mb-3">Preview</h5>
            <div class="appearance-preview"
                 style="background: @PreviewBackground; color: @PreviewTextColor; font-size: @PreviewFontSize; padding: @(_compactMode ? "0.5rem" : "1.25rem");">
                <div class="preview-header" style="border-bottom: 1px solid @(_theme == "Dark" ? "#444" : "#dee2e6"); padding-bottom: @(_compactMode ? "0.35rem" : "0.75rem"); margin-bottom: @(_compactMode ? "0.35rem" : "0.75rem");">
                    <strong>Dashboard</strong>
                    <span style="opacity: 0.6; margin-left: 1rem;">@_language</span>
                </div>
                <p style="margin-bottom: @(_compactMode ? "0.25rem" : "0.5rem");">Welcome back, Jane! Here's your activity summary.</p>
                <div class="d-flex gap-2">
                    <span class="badge" style="background: @(_theme == "Dark" ? "#0d6efd" : "#1b6ec2"); font-size: inherit;">12 Tasks</span>
                    <span class="badge" style="background: @(_theme == "Dark" ? "#198754" : "#157347"); font-size: inherit;">3 Messages</span>
                </div>
            </div>
        </div>
    };
}

